<?php namespace App\Repositories\Asset;use App\Repositories\BaseRepository;use App\Models\Asset\AssetAllocation;use Illuminate\Database\Eloquent\Collection;class AssetAllocationRepository extends BaseRepository{    public function __construct(AssetAllocation $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByAsset(int $assetId): Collection    {        return $this->findByField('asset_id', $assetId);    }    public function findByEmployee(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getActiveAllocations(): Collection    {        return $this->query()->where('status', 'active')->get();    }    public function getAllocationHistory(int $assetId): Collection    {        return $this->query()->where('asset_id', $assetId)->orderBy('allocated_at', 'desc')->get();    }    public function allocate(int $assetId, int $employeeId, array $data = []): AssetAllocation    {        $data['asset_id'] = $assetId;        $data['employee_id'] = $employeeId;        $data['allocated_at'] = $data['allocated_at'] ?? now();        $data['status'] = 'active';        return $this->create($data);    }    public function deallocate(int $allocationId): bool    {        return $this->update($allocationId, [            'status' => 'returned',            'returned_at' => now(),        ]);    }    public function getCurrentAllocation(int $assetId): ?AssetAllocation    {        return $this->query()->where('asset_id', $assetId)->where('status', 'active')->first();    }    public function getByDepartment(int $departmentId): Collection    {        return $this->query()->whereHas('employee', function ($q) use ($departmentId) {                $q->where('department_id', $departmentId);            })->get();    }}